module synchronizer
(
    input clk_a,
    input clk_b,
    input arstn,
    input brstn,
    input [3:0] data_in,
    input data_en,
    output reg [3:0] dataout
);
// TODO: Please implement the Synchronizer module based on the description and testbench provided. You can refer to the module description on the official website.
// Note: Please ensure that the clock_a and clock_b in the testbench are connected to the corresponding clock signals in the module.
// Note: The input data_en is synchronous to clock_a, and the input data_in is constant during the period when data_en is high.
// Note: The output reg dataout is synchronous to clock_b.
reg [3:0] data_reg;
reg [3:0] en_data_reg;
reg en_clap_one;
reg en_clap_two;
always @(posedge clk_a or negedge arstn) begin
    if (!arstn) begin
        data_reg <= 4'd0;
    end else begin
        data_reg <= data_in;
    end
end
always @(posedge clk_a or negedge arstn) begin
    if (!arstn) begin
        en_data_reg <= 4'd0;
    end else begin
        en_data_reg <= data_en;
    end
end
always @(posedge clk_b or negedge brstn) begin
    if (!brstn) begin
        en_clap_one <= 4'd0;
        en_clap_two <= 4'd0;
    end else begin
        en_clap_one <= en_data_reg;
        en_clap_two <= en_clap_one;
    end
end
always @(posedge clk_b or negedge brstn) begin
    if (!brstn) begin
        dataout <= 4'd0;
    end else begin
        if (en_clap_two) begin
            dataout <= data_reg;
        end else begin
            dataout <= dataout;
        end
    end
end
endmodule
